#include <bits/stdc++.h>
#define int long long
using namespace std;

int n, m, a[100005], c[100005], fa[100005];

int lowbit(int x) {
    return x & -x;
}

void add(int x, int k) {
    for(; x <= n; x += lowbit(x))
        c[x] += k;
}

int getsum(int x) {
    int sum = 0;
    for(; x; x -= lowbit(x))
        sum += c[x];
    return sum;
}

int find(int x) {
    return x == fa[x] ? x : fa[x] = find(fa[x]);
}

signed main() {
    ios::sync_with_stdio(false);
    cin.tie(0);

    cin >> n;
    for(int i = 1; i <= n; i++) {
        cin >> a[i];
        add(i, a[i]);
        fa[i] = i;
    }
    fa[n + 1] = n + 1;

    cin >> m;
    while(m--) {
        int op, l, r;
        cin >> op >> l >> r;
        if(l > r) swap(l, r);

        if(op == 0) {
            int pos = find(l);
            while(pos <= r) {
                int val = sqrt(a[pos]);
                if(val != a[pos]) {
                    add(pos, val - a[pos]);
                    a[pos] = val;
                }
                if(a[pos] <= 1) {
                    fa[pos] = find(pos + 1);
                }
                pos = find(pos + 1);
            }
        }
        else {
            cout << getsum(r) - getsum(l - 1) << '\n';
        }
    }
    return 0;
}
